import React, { Component } from 'react';

class Membro extends Component {
    constructor(props) {
        super(props);
        this.state = {
            nome: "Mateus"
        }
    }

    render() {
        return (
            <div>                
                <p>Nome: {this.state.nome}</p>
            </div>            
        );
    }
}

export default Membro;
